	private static List<String> logicalInputRoutes(TupleExpr tupleExpr) {
		return MemoInputLayout.slots(tupleExpr)
				.stream()
				.map(slot -> slot.role() + ":" + slot.use() + ":"
						+ (CascadesRewriteSupport.selectedPrefixInputIsLegal(slot.input())
								? PhysicalProperties.InputConsumption.SELECTED_PREFIX
								: PhysicalProperties.InputConsumption.ISOLATED))
				.toList();
	}

