	private static List<PhysicalProperties> normalizeInputRequirements(List<Integer> inputGroupIds,
			List<PhysicalProperties> inputRequirements, RuleKind kind) {
		List<PhysicalProperties> safeRequirements = inputRequirements == null ? List.of() : inputRequirements;
		if (safeRequirements.isEmpty()) {
			return inputGroupIds.isEmpty() || kind == RuleKind.TRANSFORMATION
					? List.of()
					: Collections.nCopies(inputGroupIds.size(), PhysicalProperties.ANY);
		}
		if (safeRequirements.size() != inputGroupIds.size()) {
			throw new IllegalArgumentException("Input requirement count " + safeRequirements.size()
					+ " does not match memo input count " + inputGroupIds.size());
		}
		return safeRequirements.stream()
				.map(requirement -> requirement == null ? PhysicalProperties.ANY : requirement)
				.toList();
	}

